// Generated by Claude Opus 4.6

import { BackupValidationResult } from '@eclipse-che/common';
import React from 'react';

import { ValidationStatusDisplay } from '@/pages/RestoreFromBackup/ExternalRegistryForm/ValidationStatusDisplay';
import { ValidationState } from '@/pages/RestoreFromBackup/helpers';
import getComponentRenderer, { screen } from '@/services/__mocks__/getComponentRenderer';

const { renderComponent } = getComponentRenderer(getComponent);

describe('ValidationStatusDisplay', () => {
  test('should render nothing for idle state', () => {
    renderComponent('idle', undefined);

    expect(screen.queryByText('Validating backup image')).not.toBeInTheDocument();
    expect(screen.queryByText('Backup image is valid')).not.toBeInTheDocument();
  });

  test('should render nothing for invalid state', () => {
    renderComponent('invalid', undefined);

    expect(screen.queryByText('Validating backup image')).not.toBeInTheDocument();
    expect(screen.queryByText('Backup image is valid')).not.toBeInTheDocument();
  });

  test('should render spinner for validating state', () => {
    renderComponent('validating', undefined);

    expect(screen.getByText(/Validating backup image/)).toBeInTheDocument();
    expect(screen.getByLabelText('Validating backup image')).toBeInTheDocument();
  });

  test('should render success message for valid state', () => {
    renderComponent('valid', undefined);

    expect(screen.getByText(/Backup image is valid and accessible/)).toBeInTheDocument();
  });

  test('should render workspace name when validation result has metadata', () => {
    const result: BackupValidationResult = {
      valid: true,
      accessible: true,
      metadata: {
        workspaceName: 'my-workspace',
        namespace: 'test-ns',
        timestamp: '2026-02-11T12:00:00Z',
        sizeBytes: 1024,
      },
    };

    renderComponent('valid', result);

    expect(screen.getByText(/Backup image is valid and accessible/)).toBeInTheDocument();
    expect(screen.getByText(/my-workspace/)).toBeInTheDocument();
  });

  test('should not render workspace name when metadata is absent', () => {
    const result: BackupValidationResult = {
      valid: true,
      accessible: true,
    };

    renderComponent('valid', result);

    expect(screen.getByText(/Backup image is valid and accessible/)).toBeInTheDocument();
  });
});

function getComponent(
  validationState: ValidationState,
  validationResult: BackupValidationResult | undefined,
) {
  return (
    <ValidationStatusDisplay
      validationState={validationState}
      validationResult={validationResult}
    />
  );
}
